script.text:
      /* <flatten type="Javascript"> */
function loadFormDir(f) {
  if (f._action == 'Edit') setItemDisable(f, 'ma_so', true);
    else if (f._action == 'New') setItemDisable(f, 'ma_so', false);
  onChange$OffBalanceSheet(f);
}
function onChange$Item(o) {
  var f = o.parentForm, name = o.field.Name;
  switch (name) {
    case 'stt':
      if (f.getItem('stt_in').value == '') f.getItem('stt_in').value = o.value;
      break;
    case 'ma_so':
      if (f.getItem('ma_so_in').value == '') f.getItem('ma_so_in').value = o.value.toUpperCase();
      break;
    case 'ngoai_bang':
      onChange$OffBalanceSheet(f, true);
      break;
    case 'kind':
      onChange$CalculateType(f, true);
      break;
    default:
      break;
  }
}
function onChange$OffBalanceSheet(f, force) {window.setTimeout(String.format('onFocus$OffBalanceSheet(\'{0}\', {1});', f._id, force ? 1 : 0), 2);}
function onFocus$OffBalanceSheet(id, force) {
  var f = $find(id), v = (f.getItem('ngoai_bang').value == 1), t1 = f.getItem('kind'), t2 = f._findButton('Ok');
  if (force) setItemLive(t1, t2, !v);
  if (v) {
    setItemDisable(f, 'kind, cach_tinh, tk, tk_du, khong_am, cong_no', v);
    setItemAllowNulls(f);
  }
  else {
    setItemDisable(f, 'kind', v);
    onChange$CalculateType(f);
  }
}
function onChange$CalculateType(f, force) {window.setTimeout(String.format('onFocus$CalculateType(\'{0}\', {1});', f._id, force ? 1 : 0), 2);}
function onFocus$CalculateType(id, force) {
  var f = $find(id), v1 = (f.getItem('kind').value == 0), v2 = (f.getItem('kind').value == 2), v3 = (f.getItem('kind').value == 1)
      , t1 = f.getItem('tk'), t3 = f.getItem('cach_tinh');
  setItemAllowNulls(f);
  setFieldsEmpty(f, 'cach_tinh', v1);
  if (force) setItemLive(t1, t3, !v1);
  setItemDisable(f, 'cach_tinh', !v1);
  setItemDisable(f, 'tk', v1);
  setItemDisable(f, 'tk_du', !v2);
  setItemDisable(f, 'cong_no, khong_am', !v3);
}
function setItemLive(t1, t2, type) {
  if (type) {if (t2.live) {t1.disabled = false; t1.focus();}}
    else {if (t1.live) {t2.disabled = false; t2.focus();}}
}
function setItemAllowNulls(f) {
  var v1 = (f.getItem('kind').value == 0 || f.getItem('ngoai_bang').value == 1), v2 = (f.getItem('kind').value == 2);
  f.getItem('tk').field.AllowNulls = v1;
  if (v1) f.setItemControlBehavior('tk', '', '');
  if (!v2) f.setItemControlBehavior('tk_du', '', '');
}
function setItemDisable(f, c, v) {
  var a = c.split(',');
  for (var i = 0; i < a.length; i++) {
    var o = f.getItem($func.trim(a[i]));
    if (o.a) $common.setVisible(o.a, !v);
    o.disabled = v;
  }
}
function setFieldsEmpty(f, c, v){
  var a = c.split(',');
  for (var i = 0; i < a.length; i++) {
    var o = f.getItem($func.trim(a[i]));
    if(!v) o.value = '';
  }
}
/* </flatten> */
      &ScriptIrregular;
